const text = $input.first().json.text || '';

// Trunca para não ultrapassar o limite de tokens do modelo
const MAX_CHARS = 8000;
const truncated = text.slice(0, MAX_CHARS);

if (!truncated.trim()) {
  throw new Error('PDF sem texto extraível. Pode ser um PDF escaneado — use o fluxo de Vision API para esse caso.');
}

return [{
  json: {
    model: 'gpt-4o',
    response_format: { type: 'json_object' },
    temperature: 0.1,
    messages: [
      {
        role: 'system',
        content: 'Você é um extrator especializado em documentos imobiliários brasileiros. Retorne APENAS JSON válido e puro, sem markdown, sem texto adicional.'
      },
      {
        role: 'user',
        content: 'Extraia os seguintes dados deste documento imobiliário:\n- titulo: string descritiva do imóvel (ex: "Apartamento 3 quartos em Copacabana")\n- valor: número inteiro em reais SEM pontos ou vírgulas (ex: 850000)\n- endereco: endereço completo\n- bairro: nome do bairro\n- cidade: nome da cidade\n- quartos: número inteiro ou null\n- suites: número inteiro ou null\n- vagas: número inteiro ou null\n- area_m2: número decimal da área útil ou null\n- iptu: valor anual do IPTU em reais como número inteiro ou null\n\nSe o formato do documento for diferente do esperado, identifique os campos pelo contexto semântico.\nRetorne APENAS JSON com essas chaves exatas, sem campos extras.\n\nDocumento:\n' + truncated
      }
    ]
  }
}];

// Extrai o conteúdo da resposta do OpenAI
const choice = $input.first().json.choices?.[0];
const content = choice?.message?.content || '{}';

let extracted;
try {
  extracted = JSON.parse(content);
} catch (e) {
  throw new Error('OpenAI retornou JSON inválido: ' + content.slice(0, 200));
}

// Gera slug único a partir do título
function toSlug(str) {
  return (str || 'imovel')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 70) + '-' + Date.now();
}

// Normaliza valor monetário (ex: "R$ 1.200.000" → 1200000)
function normalizePrice(val) {
  if (val === null || val === undefined) return 0;
  if (typeof val === 'number') return Math.round(val);
  const clean = String(val)
    .replace(/R\$\s*/gi, '')
    .replace(/\./g, '')
    .replace(',', '.')
    .trim();
  return Math.round(parseFloat(clean)) || 0;
}

// Normaliza número inteiro
function toInt(val) {
  if (val === null || val === undefined || val === '') return undefined;
  const n = parseInt(String(val), 10);
  return isNaN(n) ? undefined : n;
}

// Normaliza decimal
function toFloat(val) {
  if (val === null || val === undefined || val === '') return undefined;
  const n = parseFloat(String(val).replace(',', '.'));
  return isNaN(n) ? undefined : n;
}

const title = (extracted.titulo || extracted.title || 'Imóvel').trim();

const payload = {
  slug: toSlug(title),
  title,
  price: normalizePrice(extracted.valor ?? extracted.value ?? extracted.price),
  address: extracted.endereco || extracted.address || null,
  neighborhood: extracted.bairro || extracted.neighborhood || null,
  city: extracted.cidade || extracted.city || null,
  status: 'disponivel',
  visibility: 'publico',
  features: {
    quartos:  toInt(extracted.quartos),
    suites:   toInt(extracted.suites),
    vagas:    toInt(extracted.vagas),
    area_m2:  toFloat(extracted.area_m2),
    iptu:     toInt(extracted.iptu),
  },
  tags: [],
};

// Remove chaves undefined dentro de features
Object.keys(payload.features).forEach(k => {
  if (payload.features[k] === undefined) delete payload.features[k];
});

return [{ json: payload }];
